<h1 class="h3 mb-1">Collections</h1><p class="text-muted mb-4">Track overdue invoices, promises to pay, and customer follow-up without relying on sticky notes and optimism.</p><div class="card shadow-sm"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Invoice</th><th>Customer</th><th>Balance</th><th>Overdue</th><th>Last action</th><th>Record action</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['invoice_number'])?></strong><div class="small text-muted">Due <?=e($r['due_date'])?></div></td><td><?=e($r['display_name'])?></td><td><?=money($r['balance_due'])?></td><td><span class="badge text-bg-danger"><?=e($r['days_overdue'])?> days</span></td><td><?=e($r['last_action']?:'None')?></td><td><form method="post" action="/portal/collections/<?=e($r['id'])?>/action" class="row g-1"><?=csrf_field()?><div class="col-4"><select name="action_type" class="form-select form-select-sm"><option>email</option><option>sms</option><option>phone</option><option>letter</option><option>promise_to_pay</option><option>hold</option><option>escalation</option><option>note</option></select></div><div class="col"><input name="notes" class="form-control form-control-sm" placeholder="Notes"></div><div class="col-auto"><button class="btn btn-sm btn-primary">Save</button></div></form></td></tr><?php endforeach?></tbody></table></div></div>
